18	// runRecord is the on-disk JSON format for a FEAT-010 run file.
19	type runRecord struct {
20		ID          string   `json:"id"`
21		Layer       string   `json:"layer"`
22		Status      string   `json:"status"`
23		StartedAt   string   `json:"started_at,omitempty"`
24		CompletedAt string   `json:"completed_at,omitempty"`
25		BeadID      string   `json:"bead_id,omitempty"`
26		ArtifactID  string   `json:"artifact_id,omitempty"`
27		ParentRunID string   `json:"parent_run_id,omitempty"`
28		ChildRunIDs []string `json:"child_run_ids,omitempty"`
29	
30		// Work-layer fields
31		QueueInputs     json.RawMessage `json:"queue_inputs,omitempty"`
32		StopCondition   string          `json:"stop_condition,omitempty"`
33		SelectedBeadIDs []string        `json:"selected_bead_ids,omitempty"`
34	
35		// Try-layer fields
36		BaseRevision   string          `json:"base_revision,omitempty"`
37		ResultRevision string          `json:"result_revision,omitempty"`
38		WorktreePath   string          `json:"worktree_path,omitempty"`
39		MergeOutcome   string          `json:"merge_outcome,omitempty"`
40		CheckResults   json.RawMessage `json:"check_results,omitempty"`
41	
42		// Run-layer fields
43		PromptSummary string   `json:"prompt_summary,omitempty"`
44		PowerMin      int      `json:"power_min,omitempty"`
45		PowerMax      int      `json:"power_max,omitempty"`
46		Harness       string   `json:"harness,omitempty"`
47		Provider      string   `json:"provider,omitempty"`
48		Model         string   `json:"model,omitempty"`
49		TokensIn      int      `json:"tokens_in,omitempty"`
50		TokensOut     int      `json:"tokens_out,omitempty"`
51		CostUSD       float64  `json:"cost_usd,omitempty"`
52		DurationMs    int      `json:"duration_ms,omitempty"`
53		OutputExcerpt string   `json:"output_excerpt,omitempty"`
54		EvidenceLinks []string `json:"evidence_links,omitempty"`
55	}
