295	// synthesizeRunsFromSessions derives run-layer Run records from the agent
296	// session index. Each AgentSession entry = one agent invocation (one "run"
297	// in the three-layer model). When the session points at a bundle directory,
298	// the resulting Run is parented to the matching try-layer record.
299	func synthesizeRunsFromSessions(projectID, projectRoot string) []*ddxgraphql.Run {
300		logDir := agent.SessionLogDirForWorkDir(projectRoot)
301		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{DefaultRecent: true})
302		if err != nil {
303			return nil
304		}
305		out := make([]*ddxgraphql.Run, 0, len(entries))
306		for _, e := range entries {
307			out = append(out, sessionEntryToRun(e))
308		}
309		return out
310	}
311	
312	// sessionEntryToRun projects one SessionIndexEntry onto a run-layer Run.
313	// AgentSession is the canonical backing store under layer=run; this projection
314	// maps the fields that exist on the Run schema today (id, harness, provider,
315	// model, tokens, cost, duration, status). Session-only fields (billingMode,
316	// cached tokens, prompt/response/stderr, outcome detail) remain accessible
317	// through the AgentSession query keyed by the same id.
318	func sessionEntryToRun(e agent.SessionIndexEntry) *ddxgraphql.Run {
319		status := strings.ToLower(e.Outcome)
320		if status == "" {
321			if e.ExitCode == 0 {
322				status = "success"
323			} else {
324				status = "failure"
325			}
326		}
327		run := &ddxgraphql.Run{
328			ID:          e.ID,
329			Layer:       ddxgraphql.RunLayerRun,
330			Status:      status,
331			ChildRunIds: []string{},
332		}
333		if !e.StartedAt.IsZero() {
334			s := e.StartedAt.UTC().Format(time.RFC3339)
335			run.StartedAt = &s
336		}
337		if !e.EndedAt.IsZero() {
338			s := e.EndedAt.UTC().Format(time.RFC3339)
339			run.CompletedAt = &s
340		} else if !e.StartedAt.IsZero() && e.DurationMS > 0 {
341			s := e.StartedAt.Add(time.Duration(e.DurationMS) * time.Millisecond).UTC().Format(time.RFC3339)
342			run.CompletedAt = &s
343		}
344		if e.BeadID != "" {
345			bid := e.BeadID
346			run.BeadID = &bid
347		}
348		if e.Harness != "" {
349			h := e.Harness
350			run.Harness = &h
351		}
352		if e.Provider != "" {
353			p := e.Provider
354			run.Provider = &p
355		}
356		if e.Model != "" {
357			m := e.Model
358			run.Model = &m
359		}
360		if e.InputTokens > 0 {
361			v := e.InputTokens
362			run.TokensIn = &v
363		}
364		if e.OutputTokens > 0 {
365			v := e.OutputTokens
366			run.TokensOut = &v
367		}
368		if e.CostUSD != 0 {
369			c := e.CostUSD
370			run.CostUsd = &c
371		}
372		if e.DurationMS > 0 {
373			d := e.DurationMS
374			run.DurationMs = &d
375		}
376		// Lossless join with AgentSession: project session-only fields onto Run so
377		// run-layer queries don't lose data that lives only on AgentSession.
378		if e.BillingMode != "" {
379			bm := e.BillingMode
380			run.BillingMode = &bm
381		}
382		if e.Outcome != "" {
383			oc := e.Outcome
384			run.Outcome = &oc
385		}
386		if e.Detail != "" {
387			d := e.Detail
388			run.Detail = &d
389		}
390		var evidence []string
391		if e.BundlePath != "" {
392			evidence = append(evidence, filepath.ToSlash(e.BundlePath))
393			if parent := parentTryIDFromBundlePath(e.BundlePath); parent != "" {
394				run.ParentRunID = &parent
395			}
396		}
397		if e.NativeLogRef != "" {
398			evidence = append(evidence, filepath.ToSlash(e.NativeLogRef))
399		}
400		if len(evidence) > 0 {
401			run.EvidenceLinks = evidence
402		}
403		return run
404	}
405	
406	// parentTryIDFromBundlePath returns the synthesized try-layer Run ID
407	// ("exec-<bundle-id>") for a bundle path under .ddx/executions/, or "" when
408	// the path does not look like a bundle.
409	func parentTryIDFromBundlePath(p string) string {
410		clean := filepath.ToSlash(p)
411		prefix := filepath.ToSlash(agent.ExecuteBeadArtifactDir) + "/"
412		idx := strings.Index(clean, prefix)
413		if idx < 0 {
414			return ""
415		}
416		rest := clean[idx+len(prefix):]
417		if i := strings.Index(rest, "/"); i >= 0 {
418			rest = rest[:i]
419		}
420		if !looksLikeBundleID(rest) {
421			return ""
422		}
423		return "exec-" + rest
424	}
