426	// GetRunsGraphQL implements RunsStateProvider.
427	func (s *ServerState) GetRunsGraphQL(projectID string, filter ddxgraphql.RunFilter) []*ddxgraphql.Run {
428		var all []*ddxgraphql.Run
429	
430		if projectID != "" {
431			proj, ok := s.GetProjectByID(projectID)
432			if !ok {
433				return nil
434			}
435			all = s.loadRunsForProject(projectID, proj.Path)
436		} else {
437			for _, proj := range s.GetProjects(false) {
438				all = append(all, s.loadRunsForProject(proj.ID, proj.Path)...)
439			}
440			sort.Slice(all, func(i, j int) bool {
441				si, sj := "", ""
442				if all[i].StartedAt != nil {
443					si = *all[i].StartedAt
444				}
445				if all[j].StartedAt != nil {
446					sj = *all[j].StartedAt
447				}
448				return si > sj
449			})
450		}
451		return ddxgraphql.ApplyRunFilter(all, filter)
452	}
453	
454	// tagProjectID sets ProjectID on each run in-place.
455	func tagProjectID(runs []*ddxgraphql.Run, projectID string) []*ddxgraphql.Run {
456		for _, r := range runs {
457			pid := projectID
458			r.ProjectID = &pid
459		}
460		return runs
461	}
462	
463	// loadRunsForProject loads runs for a single project, merging the file store
464	// with synthesized execution bundle records.
465	func (s *ServerState) loadRunsForProject(projectID, projectRoot string) []*ddxgraphql.Run {
466		// Primary: FEAT-010 run store
467		stored := scanRunStore(projectRoot)
468	
469		// Secondary: synthesize run-layer records from .ddx/executions/ bundles,
470		// but only include IDs that are not already in the stored set.
471		storedIDs := make(map[string]bool, len(stored))
472		for _, r := range stored {
473			storedIDs[r.ID] = true
474		}
475	
476		synthesized := synthesizeRunsFromBundles(projectID, projectRoot)
477		for _, r := range synthesized {
478			if !storedIDs[r.ID] {
479				stored = append(stored, r)
480				storedIDs[r.ID] = true
481			}
482		}
483	
484		sessions := synthesizeRunsFromSessions(projectID, projectRoot)
485		for _, r := range sessions {
486			if !storedIDs[r.ID] {
487				stored = append(stored, r)
488				storedIDs[r.ID] = true
489			}
490		}
491	
492		// Sort newest-first by startedAt.
493		sort.Slice(stored, func(i, j int) bool {
494			si, sj := "", ""
495			if stored[i].StartedAt != nil {
496				si = *stored[i].StartedAt
497			}
498			if stored[j].StartedAt != nil {
499				sj = *stored[j].StartedAt
500			}
501			return si > sj
502		})
503		return tagProjectID(stored, projectID)
504	}
505	
506	// GetRunGraphQL implements RunsStateProvider.
507	func (s *ServerState) GetRunGraphQL(id string) (*ddxgraphql.Run, bool) {
508		if id == "" {
509			return nil, false
510		}
511		// Search all projects.
512		for _, proj := range s.GetProjects(false) {
513			runs := s.loadRunsForProject(proj.ID, proj.Path)
514			for _, r := range runs {
515				if r.ID == id {
516					s.loadRunDetail(r)
517					return r, true
518				}
519			}
520		}
521		return nil, false
522	}
