22	// SessionIndexEntry is the pointer-only session index row. Heavy prompt,
23	// response, and stderr bodies stay in execution bundles or native logs.
24	type SessionIndexEntry struct {
25		ID              string    `json:"id"`
26		ProjectID       string    `json:"projectID,omitempty"`
27		BeadID          string    `json:"beadID,omitempty"`
28		WorkerID        string    `json:"workerID,omitempty"`
29		Harness         string    `json:"harness"`
30		Provider        string    `json:"provider,omitempty"`
31		Surface         string    `json:"surface,omitempty"`
32		BaseURL         string    `json:"baseURL,omitempty"`
33		BillingMode     string    `json:"billingMode"`
34		Model           string    `json:"model,omitempty"`
35		StartedAt       time.Time `json:"startedAt"`
36		EndedAt         time.Time `json:"endedAt,omitempty"`
37		DurationMS      int       `json:"durationMs,omitempty"`
38		CostUSD         float64   `json:"cost,omitempty"`
39		CostPresent     bool      `json:"costPresent,omitempty"`
40		Tokens          int       `json:"tokens,omitempty"`
41		InputTokens     int       `json:"inputTokens,omitempty"`
42		OutputTokens    int       `json:"outputTokens,omitempty"`
43		Outcome         string    `json:"outcome,omitempty"`
44		ExitCode        int       `json:"exitCode"`
45		NativeSessionID string    `json:"nativeSessionID,omitempty"`
46		TraceID         string    `json:"traceID,omitempty"`
47		SpanID          string    `json:"spanID,omitempty"`
48		BundlePath      string    `json:"bundlePath,omitempty"`
