53		ResultRev       string    `json:"resultRev,omitempty"`
54		// ToolCalls is the normalized stream of tool_call/tool_result pairs
55		// captured at drain time (Story 16). Persisting here means resolver-time
56		// reads do not have to parse raw native logs.
57		ToolCalls []ToolCallEntry `json:"toolCalls,omitempty"`
58	}
