72	func SessionIndexDir(logDir string) string {
73		return filepath.Join(logDir, SessionIndexDirName)
74	}
75	
76	func SessionIndexShardName(t time.Time) string {
77		if t.IsZero() {
78			t = time.Now().UTC()
79		}
80		return fmt.Sprintf("sessions-%04d-%02d.jsonl", t.UTC().Year(), t.UTC().Month())
81	}
82	
83	func SessionIndexShardPath(logDir string, t time.Time) string {
84		return filepath.Join(SessionIndexDir(logDir), SessionIndexShardName(t))
85	}
