87	func ProjectIDForPath(path string) string {
88		canonical, err := filepath.Abs(path)
89		if err == nil {
90			path = canonical
91		}
92		h := sha256.Sum256([]byte(path))
93		return fmt.Sprintf("proj-%x", h[:4])
94	}
95	
96	func AppendSessionIndex(logDir string, entry SessionIndexEntry, now time.Time) error {
97		if logDir == "" {
98			return nil
99		}
100		if now.IsZero() {
101			now = time.Now().UTC()
102		}
103		if entry.ID == "" {
104			entry.ID = genSessionID()
105		}
106		if entry.StartedAt.IsZero() {
107			entry.StartedAt = now.UTC()
108		}
109		if entry.EndedAt.IsZero() && entry.DurationMS > 0 {
110			entry.EndedAt = entry.StartedAt.Add(time.Duration(entry.DurationMS) * time.Millisecond).UTC()
111		}
112		if entry.Outcome == "" {
113			if entry.ExitCode == 0 && entry.Detail == "" {
114				entry.Outcome = "success"
115			} else {
116				entry.Outcome = "failure"
117			}
118		}
119		if entry.BillingMode == "" {
120			entry.BillingMode = billingModeFor(entry.Harness, entry.Surface, entry.BaseURL)
121		}
122		if !ValidateBillingMode(entry.BillingMode) {
123			return fmt.Errorf("invalid billingMode %q", entry.BillingMode)
124		}
125		if err := os.MkdirAll(SessionIndexDir(logDir), 0o755); err != nil {
126			return err
127		}
128		data, err := json.Marshal(entry)
129		if err != nil {
130			return err
131		}
132		path := SessionIndexShardPath(logDir, now.UTC())
133		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
134		if err != nil {
135			return err
136		}
137		defer f.Close()
138		_, err = fmt.Fprintf(f, "%s\n", data)
139		return err
140	}
