305	func ReadSessionIndex(logDir string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
306		files, err := SessionIndexShardFiles(logDir, q)
307		if err != nil {
308			return nil, err
309		}
310		var out []SessionIndexEntry
311		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
312			out, err = readRecentSessionIndexFiles(files, 1000)
313		} else {
314			out, err = readSessionIndexFiles(files, q)
315		}
316		if err != nil {
317			return nil, err
318		}
319		if len(out) == 0 && q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
320			files, err = SessionIndexShardFiles(logDir, SessionIndexQuery{})
321			if err != nil {
322				return nil, err
323			}
324			out, err = readSessionIndexFiles(files, q)
325			if err != nil {
326				return nil, err
327			}
328		}
329		sort.Slice(out, func(i, j int) bool {
330			return out[i].StartedAt.After(out[j].StartedAt)
331		})
332		return out, nil
333	}
