335	func readRecentSessionIndexFiles(files []string, perFile int) ([]SessionIndexEntry, error) {
336		var out []SessionIndexEntry
337		for _, file := range files {
338			data, err := os.ReadFile(file)
339			if os.IsNotExist(err) {
340				continue
341			}
342			if err != nil {
343				return nil, err
344			}
345			lines := bytes.Split(bytes.TrimSpace(data), []byte{'\n'})
346			start := 0
347			if perFile > 0 && len(lines) > perFile {
348				start = len(lines) - perFile
349			}
350			for _, line := range lines[start:] {
351				if len(bytes.TrimSpace(line)) == 0 {
352					continue
353				}
354				var entry SessionIndexEntry
355				if err := json.Unmarshal(line, &entry); err == nil {
356					out = append(out, entry)
357				}
358			}
359		}
360		return out, nil
361	}
