363	func readSessionIndexFiles(files []string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
364		var out []SessionIndexEntry
365		for _, file := range files {
366			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
367				if !sessionIndexEntryInRange(entry, q) {
368					return nil
369				}
370				out = append(out, entry)
371				return nil
372			})
373			if err != nil {
374				return nil, err
375			}
376		}
377		return out, nil
378	}
