380	func FindSessionIndex(logDir, id string) (SessionIndexEntry, bool, error) {
381		files, err := SessionIndexShardFiles(logDir, SessionIndexQuery{})
382		if err != nil {
383			return SessionIndexEntry{}, false, err
384		}
385		for _, file := range files {
386			var found SessionIndexEntry
387			ok := false
388			err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
389				if entry.ID == id {
390					found = entry
391					ok = true
392					return fmt.Errorf("found")
393				}
394				return nil
395			})
396			if ok {
397				return found, true, nil
398			}
399			if err != nil && err.Error() != "found" {
400				return SessionIndexEntry{}, false, err
401			}
402		}
403		return SessionIndexEntry{}, false, nil
404	}
