406	func SessionIndexShardFiles(logDir string, q SessionIndexQuery) ([]string, error) {
407		dir := SessionIndexDir(logDir)
408		entries, err := os.ReadDir(dir)
409		if os.IsNotExist(err) {
410			return nil, nil
411		}
412		if err != nil {
413			return nil, err
414		}
415		var files []string
416		for _, ent := range entries {
417			if ent.IsDir() {
418				continue
419			}
420			name := ent.Name()
421			if !strings.HasPrefix(name, "sessions-") || !strings.HasSuffix(name, ".jsonl") {
422				continue
423			}
424			if !sessionShardIntersects(name, q) {
425				continue
426			}
427			files = append(files, filepath.Join(dir, name))
428		}
429		sort.Sort(sort.Reverse(sort.StringSlice(files)))
430		return files, nil
431	}
