433	func ReindexLegacySessions(projectRoot, logDir string) (int, error) {
434		legacyPath := filepath.Join(logDir, LegacySessionsFileName)
435		readPath := legacyPath
436		if _, err := os.Stat(readPath); os.IsNotExist(err) {
437			readPath = filepath.Join(logDir, LegacySessionsRenameName)
438			if _, legacyErr := os.Stat(readPath); os.IsNotExist(legacyErr) {
439				return 0, nil
440			} else if legacyErr != nil {
441				return 0, legacyErr
442			}
443		} else if err != nil {
444			return 0, err
445		}
446	
447		existing, err := existingSessionIndexIDs(logDir)
448		if err != nil {
449			return 0, err
450		}
451		count := 0
452		err = ForEachJSONL[SessionEntry](readPath, func(entry SessionEntry) error {
453			if entry.ID == "" {
454				return nil
455			}
456			if _, ok := existing[entry.ID]; ok {
457				return nil
458			}
459			idx := SessionIndexEntryFromLegacy(projectRoot, entry)
460			if err := AppendSessionIndex(logDir, idx, entry.Timestamp.UTC()); err != nil {
461				return err
462			}
463			existing[entry.ID] = struct{}{}
464			count++
465			return nil
466		})
467		if err != nil {
468			return count, err
469		}
470		if readPath == legacyPath {
471			renamed := filepath.Join(logDir, LegacySessionsRenameName)
472			if _, err := os.Stat(renamed); os.IsNotExist(err) {
473				if err := os.Rename(legacyPath, renamed); err != nil {
474					return count, err
475				}
476			}
477		}
478		return count, nil
479	}
