553	func sessionIndexEntryInRange(entry SessionIndexEntry, q SessionIndexQuery) bool {
554		if q.StartedAfter != nil && entry.StartedAt.Before(*q.StartedAfter) {
555			return false
556		}
557		if q.StartedBefore != nil && !entry.StartedAt.Before(*q.StartedBefore) {
558			return false
559		}
560		return true
561	}
