563	func sessionShardIntersects(name string, q SessionIndexQuery) bool {
564		month, ok := sessionShardMonth(name)
565		if !ok {
566			return false
567		}
568		next := month.AddDate(0, 1, 0)
569		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
570			now := time.Now().UTC()
571			current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
572			previous := current.AddDate(0, -1, 0)
573			return month.Equal(current) || month.Equal(previous)
574		}
575		if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
576			return false
577		}
578		if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
579			return false
580		}
581		return true
582	}
