584	func sessionShardMonth(name string) (time.Time, bool) {
585		if len(name) != len("sessions-2006-01.jsonl") {
586			return time.Time{}, false
587		}
588		month, err := time.Parse("2006-01", strings.TrimSuffix(strings.TrimPrefix(name, "sessions-"), ".jsonl"))
589		if err != nil {
590			return time.Time{}, false
591		}
592		return month.UTC(), true
593	}
