643	func bodiesFromResultJSON(data []byte) (string, string) {
644		var raw map[string]any
645		if err := json.Unmarshal(data, &raw); err != nil {
646			return "", ""
647		}
648		response := firstString(raw, "response", "output", "final_text", "finalText", "detail")
649		stderr := firstString(raw, "stderr", "error")
650		return response, stderr
651	}
652	
653	func bodiesFromNativeLog(path string) (string, string) {
654		f, err := os.Open(path)
655		if err != nil {
656			return "", ""
657		}
658		defer f.Close()
659		var response, stderr string
660		scanner := bufio.NewScanner(f)
661		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
662		for scanner.Scan() {
663			var raw map[string]any
664			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
665				continue
666			}
667			if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
668				response = s
669			}
670			if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
671				stderr = s
672			}
673		}
674		return response, stderr
675	}
676	
677	func firstString(raw map[string]any, keys ...string) string {
678		for _, key := range keys {
679			if s, ok := raw[key].(string); ok && s != "" {
680				return s
681			}
682		}
683		return ""
684	}
685	
686	func firstNestedString(raw map[string]any, paths ...[]string) string {
687		for _, path := range paths {
688			cur := any(raw)
689			for _, key := range path {
690				m, ok := cur.(map[string]any)
691				if !ok {
692					cur = nil
693					break
694				}
695				cur = m[key]
696			}
697			if s, ok := cur.(string); ok && s != "" {
698				return s
699			}
700		}
701		return ""
702	}
