63	// bundleIDForRunID maps a Run.id to its bundle directory name under
64	// .ddx/executions/, or "" when the run has no bundle.
65	//
66	// Three input shapes are recognized:
67	//   - "exec-<bundleID>"             → try-layer synthesised from bundle directory
68	//   - run-layer session ID with a BundlePath pointing under .ddx/executions/
69	//   - bundle ID directly (for caller convenience)
70	func bundleIDForRunID(projectRoot, runID string) string {
71		if strings.HasPrefix(runID, "exec-") {
72			return strings.TrimPrefix(runID, "exec-")
73		}
74		// Try resolving the run-layer session entry.
75		logDir := agent.SessionLogDirForWorkDir(projectRoot)
76		entry, ok, err := agent.FindSessionIndex(logDir, runID)
77		if err == nil && ok && entry.BundlePath != "" {
78			return bundleIDFromPath(entry.BundlePath)
79		}
80		return ""
81	}
82	
83	// bundleIDFromPath extracts the bundle directory leaf name from a BundlePath
84	// of the form ".ddx/executions/<bundleID>" or ".ddx/executions/<bundleID>/...".
85	func bundleIDFromPath(p string) string {
86		clean := filepath.ToSlash(p)
87		prefix := filepath.ToSlash(agent.ExecuteBeadArtifactDir) + "/"
88		idx := strings.Index(clean, prefix)
89		if idx < 0 {
90			return ""
91		}
92		rest := clean[idx+len(prefix):]
93		if i := strings.Index(rest, "/"); i >= 0 {
94			rest = rest[:i]
95		}
96		if !looksLikeBundleID(rest) {
97			return ""
98		}
99		return rest
100	}
101	
102	// resolveRunBundlePath canonicalises a user-supplied path (relative to the
103	// bundle root) and returns the absolute filesystem path inside the bundle.
104	// It rejects:
105	//   - absolute paths
106	//   - paths containing ".." that escape the root
107	//   - symlink targets that resolve outside the root
108	//
109	// All three rejection modes return errRunBundleOutsideRoot. The path argument
110	// must use forward slashes (or be normalisable to them).
111	func resolveRunBundlePath(bundleRoot, path string) (string, error) {
112		if path == "" {
113			return "", errRunBundleOutsideRoot
114		}
115		if filepath.IsAbs(path) || strings.HasPrefix(path, "/") {
116			return "", errRunBundleOutsideRoot
117		}
118		clean := filepath.Clean(filepath.FromSlash(path))
119		if clean == "." || clean == ".." || strings.HasPrefix(clean, ".."+string(filepath.Separator)) {
120			return "", errRunBundleOutsideRoot
121		}
122		full := filepath.Join(bundleRoot, clean)
123		// Re-clean and confirm it sits under bundleRoot.
124		full = filepath.Clean(full)
125		rel, err := filepath.Rel(bundleRoot, full)
126		if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
127			return "", errRunBundleOutsideRoot
128		}
129		// If the file (or any parent) is a symlink, confirm the eval'd target
130		// also remains inside the canonical bundleRoot. Missing files are OK to
131		// pass through here — the caller will return 404 when reading.
132		if eval, err := filepath.EvalSymlinks(full); err == nil {
133			evalClean := filepath.Clean(eval)
134			rel2, err := filepath.Rel(bundleRoot, evalClean)
135			if err != nil || rel2 == ".." || strings.HasPrefix(rel2, ".."+string(filepath.Separator)) {
136				return "", errRunBundleOutsideRoot
137			}
138		}
139		return full, nil
140	}
141	
142	// listRunBundleFiles walks the bundle root and returns one RunBundleFile per
143	// regular file. Symlinks pointing outside the root are skipped.
144	func listRunBundleFiles(bundleRoot string) []*ddxgraphql.RunBundleFile {
145		var out []*ddxgraphql.RunBundleFile
146		if bundleRoot == "" {
147			return out
148		}
149		_ = filepath.Walk(bundleRoot, func(p string, info os.FileInfo, err error) error {
150			if err != nil || info == nil {
151				return nil
152			}
153			if info.IsDir() {
154				return nil
155			}
156			// Skip anything that, after symlink resolution, escapes the root.
157			if eval, err := filepath.EvalSymlinks(p); err == nil {
158				rel, err := filepath.Rel(bundleRoot, filepath.Clean(eval))
159				if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
160					return nil
161				}
162			}
163			rel, err := filepath.Rel(bundleRoot, p)
164			if err != nil {
165				return nil
166			}
167			size := int(info.Size())
168			mt := mimeTypeForPath(rel)
169			out = append(out, &ddxgraphql.RunBundleFile{
170				Path:     filepath.ToSlash(rel),
171				Size:     size,
172				MimeType: mt,
173			})
174			return nil
175		})
176		sort.Slice(out, func(i, j int) bool { return out[i].Path < out[j].Path })
177		return out
178	}
179	
180	// readRunBundleFile resolves path under bundleRoot and returns the file's
181	// inline content (when allowed) plus size/truncated metadata. The bool return
182	// is false when the file does not exist (404) or fails the confinement check.
183	func readRunBundleFile(bundleRoot, path string) (*ddxgraphql.RunBundleFileContent, bool) {
184		full, err := resolveRunBundlePath(bundleRoot, path)
185		if err != nil {
186			return nil, false
187		}
188		info, err := os.Stat(full)
189		if err != nil || info.IsDir() {
190			return nil, false
191		}
192		size := int(info.Size())
193		mt := mimeTypeForPath(path)
194		out := &ddxgraphql.RunBundleFileContent{
195			Path:      filepath.ToSlash(path),
196			SizeBytes: size,
197			Truncated: false,
198			MimeType:  mt,
199		}
200		if !runBundleInlineAllowed(path) || size > runBundleInlineMaxBytes {
201			out.Truncated = true
202			return out, true
203		}
204		data, err := os.ReadFile(full)
205		if err != nil {
206			out.Truncated = true
207			return out, true
208		}
209		body := string(data)
210		out.Content = &body
211		return out, true
212	}
213	
214	// runBundleInlineAllowed reports whether a path qualifies for inline content
215	// based on extension and exact-filename whitelist rules from Story 16.
216	func runBundleInlineAllowed(path string) bool {
217		base := strings.ToLower(filepath.Base(filepath.FromSlash(path)))
218		if runBundleInlineExtensions[base] {
219			return true
220		}
221		ext := strings.ToLower(filepath.Ext(base))
222		return runBundleInlineExtensions[ext]
223	}
224	
225	// mimeTypeForPath returns a best-effort MIME type from the file extension.
226	// Falls back to application/octet-stream when nothing matches.
227	func mimeTypeForPath(path string) string {
228		ext := strings.ToLower(filepath.Ext(path))
229		switch ext {
230		case ".md":
231			return "text/markdown"
232		case ".txt":
233			return "text/plain"
234		case ".json":
235			return "application/json"
236		case ".jsonl":
237			return "application/x-ndjson"
238		case ".log":
239			return "text/plain"
240		}
241		if mt := mime.TypeByExtension(ext); mt != "" {
242			return mt
243		}
244		return "application/octet-stream"
245	}
246	
247	// loadRunDetail enriches a Run model with the body fields that are only
248	// loaded for run(id:) lookups: prompt, response, stderr, bundleFiles. It is a
249	// no-op when the run has no associated bundle / session bodies.
250	func (s *ServerState) loadRunDetail(run *ddxgraphql.Run) {
251		if run == nil {
252			return
253		}
254		bundleRoot, projectRoot, ok := s.runBundleRoot(run.ID)
255		if ok {
256			run.BundleFiles = listRunBundleFiles(bundleRoot)
257		} else {
258			run.BundleFiles = []*ddxgraphql.RunBundleFile{}
259		}
260		// Populate prompt/response/stderr from the session bodies, when we can
261		// resolve a session entry for this run.
262		if projectRoot == "" {
263			// Fall back to scanning all projects for an entry by run id.
264			for _, proj := range s.GetProjects(false) {
265				if entry, ok, err := agent.FindSessionIndex(agent.SessionLogDirForWorkDir(proj.Path), run.ID); err == nil && ok {
266					bodies := agent.LoadSessionBodies(proj.Path, entry)
267					assignBodies(run, bodies)
268					return
269				}
270			}
271			return
272		}
273		logDir := agent.SessionLogDirForWorkDir(projectRoot)
274		if entry, ok, err := agent.FindSessionIndex(logDir, run.ID); err == nil && ok {
275			bodies := agent.LoadSessionBodies(projectRoot, entry)
276			assignBodies(run, bodies)
277			return
278		}
279		// Try-layer synthesised IDs ("exec-<bundleID>") have no session entry but
280		// can pull prompt/result.json directly from the bundle.
281		if strings.HasPrefix(run.ID, "exec-") {
282			if data, err := os.ReadFile(filepath.Join(bundleRoot, "prompt.md")); err == nil {
283				s := string(data)
284				run.Prompt = &s
285			}
286			if data, err := os.ReadFile(filepath.Join(bundleRoot, "result.json")); err == nil {
287				s := string(data)
288				run.Response = &s
289			}
290		}
291	}
292	
293	func assignBodies(run *ddxgraphql.Run, bodies agent.SessionBodies) {
294		if bodies.Prompt != "" {
295			s := bodies.Prompt
296			run.Prompt = &s
297		}
298		if bodies.Response != "" {
299			s := bodies.Response
300			run.Response = &s
301		}
302		if bodies.Stderr != "" {
303			s := bodies.Stderr
304			run.Stderr = &s
305		}
306	}
307	
308	// GetRunToolCallsGraphQL returns the normalized ToolCallEntry slice persisted
309	// at drain time for a run, projected onto the GraphQL RunToolCall type.
310	//
311	// For run-layer Runs, the source is the per-session ToolCalls field on
312	// SessionIndexEntry. For try-layer Runs ("exec-<bundleID>"), we union the
313	// child-session tool calls (multiple agent invocations may share a try).
314	func (s *ServerState) GetRunToolCallsGraphQL(id string) []*ddxgraphql.RunToolCall {
315		if id == "" {
316			return nil
317		}
318		for _, proj := range s.GetProjects(false) {
319			logDir := agent.SessionLogDirForWorkDir(proj.Path)
320			// Run-layer: direct lookup by session id.
321			if entry, ok, _ := agent.FindSessionIndex(logDir, id); ok {
322				return runToolCallsFromEntry(entry.ToolCalls)
323			}
324			// Try-layer: union all sessions that point at the same bundle.
325			if strings.HasPrefix(id, "exec-") {
326				bundleID := strings.TrimPrefix(id, "exec-")
327				entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
328				if err != nil {
329					continue
330				}
331				var all []agent.ToolCallEntry
332				for _, e := range entries {
333					if bundleIDFromPath(e.BundlePath) != bundleID {
334						continue
335					}
336					all = append(all, e.ToolCalls...)
337				}
338				if len(all) > 0 {
339					return runToolCallsFromEntry(all)
340				}
341			}
342		}
343		return nil
344	}
345	
346	func runToolCallsFromEntry(entries []agent.ToolCallEntry) []*ddxgraphql.RunToolCall {
347		out := make([]*ddxgraphql.RunToolCall, 0, len(entries))
348		for i, e := range entries {
349			call := &ddxgraphql.RunToolCall{
350				ID:    formatRunToolCallID(i),
351				Seq:   i,
352				Tool:  e.Tool,
353				Input: e.Input,
354			}
355			if e.Output != "" {
356				s := e.Output
357				call.Output = &s
358			}
359			if e.Error != "" {
360				s := e.Error
361				call.Error = &s
362			}
363			if e.Duration > 0 {
364				d := e.Duration
365				call.DurationMs = &d
366			}
367			out = append(out, call)
368		}
369		return out
370	}
371	
372	func formatRunToolCallID(seq int) string {
373		return "rtc-" + strconv.Itoa(seq)
374	}
375	
376	// GetRunBundleFileGraphQL is the data-layer entry point for the
377	// runBundleFile(id, path) resolver. Returns (nil, false) when the run is
378	// unknown, the path fails confinement, or the file does not exist.
379	func (s *ServerState) GetRunBundleFileGraphQL(id, path string) (*ddxgraphql.RunBundleFileContent, bool) {
380		bundleRoot, _, ok := s.runBundleRoot(id)
381		if !ok {
382			return nil, false
383		}
384		return readRunBundleFile(bundleRoot, path)
385	}
