550	// ExtractUsage parses structured token usage from agent output.
551	// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
552	// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
553	// Returns zero-value UsageData if parsing fails or the harness is unsupported.
554	func ExtractUsage(harnessName string, output string) UsageData {
555		switch harnessName {
